    prizes: ["$0", "$100", "$500", "$1,000", "$2,000", "$3,000", "$5,000", "$7,000", "$10,000", "$15,000", "$25,000", "$50,000", "$100,000", "$250,000", "$500,000", "$1,000,000"],
