var media_url = '';
var GameApp = {
    audio: {
        gioithieu: media_url + "assets/sounds/gioithieu.ogg",
        nhacnen: media_url + "assets/sounds/nhacnen.ogg",
        startgame: media_url + "assets/sounds/startgame.mp3",
        chucmung: media_url + "assets/sounds/chucmung.ogg",
        sansang: media_url + "assets/sounds/sansang.mp3",
        chonnguoimayman: media_url + "assets/sounds/chonnguoimayman.ogg",
        dung5: media_url + "assets/sounds/dung5.ogg",
        dung: media_url + "assets/sounds/dung.ogg",
        sai: media_url + "assets/sounds/sai.ogg",
    },
    state: {
        players: [],
        currentPlayer: null,
        currentQuestionIndex: 0,
        currentRenderedQuestion: null,
        currentQuestionSet: [],
        startIndexForThisTurn: 0,
        isAnswering: false,

        readyModal: null, confirmChangeModal: null, confirmStopModal: null,
        alertModal: null, lifelineModal: null, settingsModal: null, leaderboardModal: null, confirmBackModal: null,

        pendingAction: null, pendingPlayerIdx: null,

        timeLeft: 60,
        timerInterval: null,
        settings: {
            timeLimit: 60,
            shuffleAnswers: false,
            allowPlayedRandom: true,
            questionCount: 15,
            bgMusic: false
        },

        hasLifeline5050: true, hasLifelineTeacher: true, hasLifelineAudience: true,
    },

    init: function (){
        var self = this;
        self.loadSettings();
        self.state.players = self.getPlayersWithAchievements();

        self.state.readyModal = new bootstrap.Modal(document.getElementById('playerReadyModal'));
        self.state.confirmChangeModal = new bootstrap.Modal(document.getElementById('confirmChangeModal'));
        self.state.confirmStopModal = new bootstrap.Modal(document.getElementById('confirmStopModal'));
        self.state.alertModal = new bootstrap.Modal(document.getElementById('alertModal'));
        self.state.lifelineModal = new bootstrap.Modal(document.getElementById('lifelineModal'));
        self.state.settingsModal = new bootstrap.Modal(document.getElementById('settingsModal'));
        self.state.leaderboardModal = new bootstrap.Modal(document.getElementById('leaderboardModal'));
        self.state.confirmBackModal = new bootstrap.Modal(document.getElementById('confirmBackModal'));

        self.initEvent();
        self.renderMoneyTree();
        self.switchScreen('screen_welcome');
        self.renderPlayer();
    },
    saveSettings: function() {
        localStorage.setItem('tphd_settings', JSON.stringify(this.state.settings));
    },
    loadSettings: function() {
        let s = JSON.parse(localStorage.getItem('tphd_settings') || '{}');
        this.state.settings = {
            timeLimit: s.timeLimit !== undefined ? parseInt(s.timeLimit) : 60,
            shuffleAnswers: s.shuffleAnswers !== undefined ? s.shuffleAnswers : false,
            allowPlayedRandom: s.allowPlayedRandom !== undefined ? s.allowPlayedRandom : true,
            questionCount: s.questionCount !== undefined ? parseInt(s.questionCount) : 15
        };
    },

    getPlayersWithAchievements: function() {
        let savedScores = JSON.parse(localStorage.getItem('tphd_records_money') || '{}');
        return GameConfig.getPlayers().map(p => {
            p.score = savedScores.hasOwnProperty(p.name) ? savedScores[p.name] : null;
            return p;
        });
    },

    initEvent: function () {
        var self = this;

        $('#musicBtn').on('click', function () {
            var audio = document.getElementById("bg-music-player");
            if(audio && audio.paused) {
                self.playBgMusic({'url':self.audio.gioithieu}, () => {});
            }

            if(self.state.settings.bgMusic) {
                self.state.settings.bgMusic = false;
                $('#musicBtn').removeClass('on').addClass('off');
                var audio = document.getElementById("bg-music-player");
                if (audio) {
                    audio.volume = 0;
                }
            } else {
                self.state.settings.bgMusic = true;
                $('#musicBtn').removeClass('off').addClass('on');
                var audio = document.getElementById("bg-music-player");
                if (audio) {
                    audio.volume = 0.5;
                }
            }
            self.saveSettings();

        });

        $('#startBtn').on('click', function (){
            self.switchScreen('screen_gameplay');
            self.resetGameplayState();
            self.playBgMusic({'url':self.audio.nhacnen}, () => {});
            self.playMusic({'url':self.audio.startgame}, () => {});
        });

        $('#backWelcomeBtn').on('click', function() {
            if (self.state.currentPlayer && self.state.isAnswering) return;
            if (self.state.currentPlayer) {
                self.stopTimer();
                self.state.confirmBackModal.show();
            } else {
                self.resetGameplayState();
                self.switchScreen('screen_welcome');
            }
        });

        $('#confirmBackBtn').on('click', function() {
            $('#confirmBackModal').data('confirmed', true);
            self.state.confirmBackModal.hide();
            self.resetGameplayState();
            self.switchScreen('screen_welcome');
        });

        $('#confirmBackModal').on('hidden.bs.modal', function () {
            if (self.state.currentPlayer && !self.state.isAnswering && !$(this).data('confirmed')) {
                self.resumeTimer();
            }
            $(this).data('confirmed', false);
        });

        // --- CÀI ĐẶT & RESET ---
        $('#btnSettings').on('click', function() {
            $('#settingQuestionCount').val(self.state.settings.questionCount);
            $('#settingTimeLimit').val(self.state.settings.timeLimit);
            $('#settingShuffle').prop('checked', self.state.settings.shuffleAnswers);
            $('#settingAllowPlayed').prop('checked', self.state.settings.allowPlayedRandom);
            self.state.settingsModal.show();
        });

        $('#saveSettingsBtn').on('click', function() {
            self.state.settings.questionCount = parseInt($('#settingQuestionCount').val()) || 15;
            self.state.settings.timeLimit = parseInt($('#settingTimeLimit').val()) || 60;
            self.state.settings.shuffleAnswers = $('#settingShuffle').prop('checked');
            self.state.settings.allowPlayedRandom = $('#settingAllowPlayed').prop('checked');

            self.saveSettings();
            self.renderMoneyTree();
            self.state.settingsModal.hide();
            self.showAlert("Đã lưu các tùy chọn cài đặt thành công!");
        });

        // Nút xóa toàn bộ Game
        $('#resetGameBtn').on('click', function() {
            if (confirm("CẢNH BÁO: Hành động này sẽ xóa TOÀN BỘ lịch sử điểm số, vị trí câu hỏi và cài đặt. Bạn có chắc chắn muốn làm mới toàn bộ trò chơi không?")) {
                localStorage.removeItem('tphd_settings');
                localStorage.removeItem('tphd_records_money');
                localStorage.removeItem('tphd_used_q_index');
                location.reload();
            }
        });

        $('#leaderboard_btn').on('click', function() {
            self.state.leaderboardModal.show();
        });

        $('#randPlayerBtn').on('click', function (){
            if (self.state.isAnswering) return;
            if (self.state.currentPlayer) {
                self.stopTimer();
                self.state.pendingAction = 'random';
                $('#currentPlayingName').text(self.state.currentPlayer.name);
                self.state.confirmChangeModal.show();
            } else {
                self.doRandomPlayer();
            }
        });

        $('#player_list').on('click','.player', function (){
            if (self.state.isAnswering) return;
            let pIdx = parseFloat($(this).attr('data-id')) - 1;
            if (self.state.currentPlayer) {
                self.stopTimer();
                self.state.pendingAction = 'manual';
                self.state.pendingPlayerIdx = pIdx;
                $('#currentPlayingName').text(self.state.currentPlayer.name);
                self.state.confirmChangeModal.show();
            } else {
                self.doManualSelect(pIdx);
            }
        });

        $('#confirmChangeBtn').on('click', function() {
            $('#confirmChangeModal').data('confirmed', true);
            self.state.confirmChangeModal.hide();

            $('#question_content').text('Đang thiết lập lượt chơi mới...');
            $('.ans-btn').hide();
            $('#stopGameBtn').hide();
            self.state.currentQuestionIndex = 0;
            self.updateMoneyTree();

            if (self.state.pendingAction === 'random') {
                self.doRandomPlayer();
            } else if (self.state.pendingAction === 'manual') {
                self.doManualSelect(self.state.pendingPlayerIdx);
            }
        });

        $('#confirmChangeModal').on('hidden.bs.modal', function () {
            if (self.state.currentPlayer && !self.state.isAnswering && !$(this).data('confirmed')) {
                self.resumeTimer();
            }
            $(this).data('confirmed', false);
        });

        $('#confirmReadyBtn').on('click', function() {
            self.playMusic({'url':self.audio.sansang}, () => {});
            self.state.readyModal.hide();
            $('#stopGameBtn').show();
            self.startPlayerTurn();
        });

        $('#stopGameBtn').on('click', function() {
            if (self.state.isAnswering || !self.state.currentPlayer) return;
            self.stopTimer();
            self.state.confirmStopModal.show();
        });

        $('#confirmStopBtn').on('click', function() {
            $('#confirmStopModal').data('confirmed', true);
            self.state.confirmStopModal.hide();
            let achievementIdx = self.state.currentQuestionIndex;
            self.endGameWithRecord(achievementIdx, "Bạn đã bảo toàn thành công tiền thưởng hiện tại.");
        });

        $('#confirmStopModal').on('hidden.bs.modal', function () {
            if (self.state.currentPlayer && !self.state.isAnswering && !$(this).data('confirmed')) {
                self.resumeTimer();
            }
            $(this).data('confirmed', false);
        });

        // --- TRỢ GIÚP ---
        $('#ll-5050').on('click', function() {
            if (!self.state.currentPlayer || self.state.isAnswering || !self.state.hasLifeline5050) return;
            self.state.hasLifeline5050 = false;
            $(this).addClass('used');

            let qData = self.state.currentRenderedQuestion;
            let correctIdx = qData.answer;
            let wrongIndexes = [0, 1, 2, 3].filter(idx => idx !== correctIdx);

            wrongIndexes.sort(() => Math.random() - 0.5);
            let toHide = wrongIndexes.slice(0, 2);

            toHide.forEach(idx => {
                $('#ans_' + idx).html('');
                $('.ans-btn[data-idx="'+idx+'"]').addClass('disabled-ans');
            });
        });

        $('#ll-teacher').on('click', function() {
            if (!self.state.currentPlayer || self.state.isAnswering || !self.state.hasLifelineTeacher) return;
            self.state.hasLifelineTeacher = false;
            $(this).addClass('used');

            $('#lifelineModalTitle').text('HỎI Ý KIẾN GIÁO VIÊN');
            $('#lifelineModalBody').text('Xin mời thầy/cô giáo đưa ra gợi ý cho người chơi ở câu hỏi này!');

            self.stopTimer();
            self.state.lifelineModal.show();
        });

        $('#ll-audience').on('click', function() {
            if (!self.state.currentPlayer || self.state.isAnswering || !self.state.hasLifelineAudience) return;
            self.state.hasLifelineAudience = false;
            $(this).addClass('used');

            $('#lifelineModalTitle').text('HỎI Ý KIẾN CÁC BẠN');
            $('#lifelineModalBody').text('Hãy cùng tham khảo ý kiến của các bạn trong lớp cho câu hỏi này nhé!');

            self.stopTimer();
            self.state.lifelineModal.show();
        });

        $('#lifelineModal').on('hidden.bs.modal', function () {
            if (self.state.currentPlayer && !self.state.isAnswering) {
                self.resumeTimer();
            }
        });

        $('.ans-btn').on('click', function() {
            if (self.state.isAnswering || !self.state.currentPlayer || $(this).hasClass('disabled-ans')) return;
            let selectedIdx = $(this).data('idx');
            self.handleAnswer(selectedIdx, $(this));
        });
    },

    // --- LOGIC ĐỒNG HỒ ---
    startTimer: function() {
        this.stopTimer();
        this.state.timeLeft = this.state.settings.timeLimit;
        $('#countdown-timer').text(this.state.timeLeft).css({'color': '#FFEB3B', 'border-color': '#FFEB3B'});
        this.resumeTimer();
    },

    stopTimer: function() {
        if (this.state.timerInterval) {
            clearInterval(this.state.timerInterval);
            this.state.timerInterval = null;
        }
    },

    resumeTimer: function() {
        var self = this;
        if(self.state.timeLeft > 0 && !self.state.isAnswering) {
            self.stopTimer();
            self.state.timerInterval = setInterval(function() {
                self.state.timeLeft--;
                $('#countdown-timer').text(self.state.timeLeft);

                if (self.state.timeLeft <= 10) {
                    $('#countdown-timer').css({'color': '#ff4d4d', 'border-color': '#ff4d4d'});
                } else {
                    $('#countdown-timer').css({'color': '#FFEB3B', 'border-color': '#FFEB3B'});
                }

                if (self.state.timeLeft <= 0) {
                    self.stopTimer();
                    self.handleTimeout();
                }
            }, 1000);
        }
    },

    handleTimeout: function() {
        var self = this;
        self.state.isAnswering = true;
        let qData = self.state.currentRenderedQuestion;
        let correctIdx = qData.answer;

        $('.ans-btn[data-idx="'+correctIdx+'"]').addClass('correct');

        let milestoneIdx = (self.state.currentQuestionIndex >= 10) ? 10 : ((self.state.currentQuestionIndex >= 5) ? 5 : 0);

        setTimeout(function() {
            self.endGameWithRecord(milestoneIdx, "HẾT GIỜ!<br>Bạn đã không đưa ra câu trả lời kịp thời.");
        }, 2500);
    },

    showAlert: function(message, callback) {
        var self = this;
        $('#alertMessage').html(message.replace(/\n/g, '<br>'));
        self.state.alertModal.show();

        $('#alertModal').off('hidden.bs.modal').on('hidden.bs.modal', function () {
            if (typeof callback === 'function') callback();
        });
    },

    doRandomPlayer: function() {
        var self = this;
        let pool = self.state.players;

        if (!self.state.settings.allowPlayedRandom) {
            pool = self.state.players.filter(p => p.score === null);
        }

        if (pool.length === 0) {
            self.showAlert("Tất cả mọi người đều đã chơi!<br>Vui lòng bật tính năng 'Chọn cả người đã chơi rồi' trong phần Cài đặt.");
            self.state.isAnswering = false;
            return;
        }

        self.playMusic({'url':self.audio.chonnguoimayman}, () => {});

        let ranIn = 20;
        let ranInTime = 3000;
        self.state.isAnswering = true;

        for(let i=1;i<=ranIn;i++) {
            const randPlayer = pool[Math.floor(Math.random() * pool.length)];
            setTimeout(function (){
                let pContainer = $('#player_list');
                pContainer.find('.player').removeClass('active');

                let targetPlayer = pContainer.find('.player[data-id="'+randPlayer.id+'"]');
                targetPlayer.addClass('active');
                targetPlayer.get(0).scrollIntoView({ behavior: 'smooth', block: 'center' });

                if(i == ranIn) {
                    self.setCurrentPlayer(randPlayer.id - 1);
                    self.showReadyPopup();
                }
            }, i * (ranInTime / ranIn));
        }
    },

    doManualSelect: function(pIdx) {
        this.setCurrentPlayer(pIdx);
        this.showReadyPopup();
    },

    showReadyPopup: function() {
        var self = this;
        if(this.state.currentPlayer) {
            $('#readyPlayerName').text(this.state.currentPlayer.name);
            this.state.readyModal.show();
            self.playMusic({'url':self.audio.chucmung}, () => {});
        }
    },

    resetGameplayState: function() {
        this.state.currentPlayer = null;
        this.state.currentQuestionIndex = 0;
        this.state.isAnswering = false;

        this.state.hasLifeline5050 = true;
        this.state.hasLifelineTeacher = true;
        this.state.hasLifelineAudience = true;
        $('#ll-5050, #ll-teacher, #ll-audience').removeClass('used');

        this.stopTimer();
        $('#countdown-timer').text(this.state.settings.timeLimit).css({'color': '#FFEB3B', 'border-color': '#FFEB3B'});

        $('#player_list .player').removeClass('active');
        $('#question_content').text('Vui lòng chọn người chơi từ danh sách hoặc nút Chọn người may mắn.');
        $('.ans-btn .qa-box-inner').html('');
        $('.ans-btn').removeClass('selected correct wrong disabled-ans');
        $('#stopGameBtn').hide();
        this.updateMoneyTree();
    },

    startPlayerTurn: function() {
        var self = this;
        let count = self.state.settings.questionCount;
        let usedIndex = parseInt(localStorage.getItem('tphd_used_q_index') || '0');
        let totalQ = GameConfig.questionData.length;

        // KIỂM TRA SỐ LƯỢNG CÂU CÒN LẠI TRONG KHO
        if (totalQ - usedIndex < count) {
            usedIndex = 0;
            self.showAlert("Không đủ câu hỏi trong kho dữ liệu cho lượt chơi mới. Hệ thống sẽ reset lại toàn bộ câu hỏi từ đầu!", function() {
                self._doStartTurn(usedIndex, count);
            });
        } else {
            self._doStartTurn(usedIndex, count);
        }
    },

    _doStartTurn: function(usedIndex, count) {
        var self = this;

        // Cắt nguyên 1 bộ câu hỏi
        let newSet = GameConfig.questionData.slice(usedIndex, usedIndex + count);

        self.state.startIndexForThisTurn = usedIndex;
        localStorage.setItem('tphd_used_q_index', usedIndex + count);

        self.state.currentQuestionSet = newSet;
        self.state.currentQuestionIndex = 0;
        self.state.isAnswering = false;
        $('.ans-btn').show();
        self.loadQuestion();
    },

    loadQuestion: function() {
        var self = this;
        let count = self.state.settings.questionCount;
        let qDataRaw = self.state.currentQuestionSet[self.state.currentQuestionIndex];

        if(!qDataRaw || self.state.currentQuestionIndex >= count) {
            self.stopTimer();
            setTimeout(() => {
                self.endGameWithRecord(count, "CHÚC MỪNG CHIẾN THẮNG!<br>BẠN ĐÃ LÀ TRIỆU PHÚ!");
            }, 1000);
            return;
        }

        // Xáo trộn đáp án nếu có cài đặt
        let qData = JSON.parse(JSON.stringify(qDataRaw));
        if (self.state.settings.shuffleAnswers) {
            let correctText = qData.opts[qData.answer];
            for (let i = qData.opts.length - 1; i > 0; i--) {
                const j = Math.floor(Math.random() * (i + 1));
                [qData.opts[i], qData.opts[j]] = [qData.opts[j], qData.opts[i]];
            }
            qData.answer = qData.opts.indexOf(correctText);
        }
        self.state.currentRenderedQuestion = qData;
        self.state.isAnswering = false;

        $('.ans-btn').removeClass('selected correct wrong disabled-ans');
        $('.qa-box-inner[id^="ans_"]').css('visibility', 'visible');

        $('#question_content').text("Câu " + (self.state.currentQuestionIndex + 1) + ": " + qData.q);
        let prefixes = ['A', 'B', 'C', 'D'];
        qData.opts.forEach((opt, idx) => {
            $('#ans_' + idx).text(prefixes[idx] + '. ' + opt);
        });

        self.updateMoneyTree();
        self.startTimer();
    },

    handleAnswer: function(selectedIdx, $el) {
        var self = this;
        self.state.isAnswering = true;
        self.stopTimer();

        let qData = self.state.currentRenderedQuestion;
        let correctIdx = qData.answer;
        let maxCount = self.state.settings.questionCount;

        $el.addClass('selected');

        setTimeout(function() {
            if (selectedIdx === correctIdx) {
                if((self.state.currentQuestionIndex + 1) % 5 === 0) {
                    self.playMusic({'url':self.audio.dung5}, () => {});
                } else {
                    self.playMusic({'url':self.audio.dung}, () => {});
                }
                $el.removeClass('selected').addClass('correct');
                setTimeout(function() {
                    self.state.currentQuestionIndex++;
                    if (self.state.currentQuestionIndex >= maxCount) {
                        self.endGameWithRecord(maxCount, "CHÚC MỪNG CHIẾN THẮNG!<br>BẠN ĐÃ LÀ TRIỆU PHÚ!");
                    } else {
                        self.loadQuestion();
                    }
                }, 1000);
            } else {
                self.playMusic({'url':self.audio.sai}, () => {});
                $el.removeClass('selected').addClass('wrong');
                $('.ans-btn[data-idx="'+correctIdx+'"]').addClass('correct');

                let milestoneIdx = (self.state.currentQuestionIndex >= 10) ? 10 : ((self.state.currentQuestionIndex >= 5) ? 5 : 0);

                setTimeout(function() {
                    self.endGameWithRecord(milestoneIdx, "RẤT TIẾC, CÂU TRẢ LỜI KHÔNG CHÍNH XÁC!");
                }, 1500);
            }
        }, 1000);
    },

    endGameWithRecord: function(levelIdx, message) {
        var self = this;
        self.stopTimer();
        let playerName = self.state.currentPlayer.name;

        // Bảo lưu các câu chưa hiển thị trong bộ câu hỏi
        let questionsSeen = self.state.currentQuestionIndex + 1;
        if (questionsSeen > self.state.settings.questionCount) {
            questionsSeen = self.state.settings.questionCount;
        }
        let newUsedIndex = self.state.startIndexForThisTurn + questionsSeen;
        localStorage.setItem('tphd_used_q_index', newUsedIndex.toString());

        let prizeStr = GameConfig.prizes[levelIdx] || "$0";
        let prizeValue = parseInt(prizeStr.replace(/[^0-9]/g, '')) || 0;

        let savedScores = JSON.parse(localStorage.getItem('tphd_records_money') || '{}');

        // Cộng dồn tiền thưởng
        if (typeof savedScores[playerName] === 'undefined') {
            savedScores[playerName] = prizeValue;
        } else {
            savedScores[playerName] += prizeValue;
        }
        localStorage.setItem('tphd_records_money', JSON.stringify(savedScores));

        self.state.players = self.getPlayersWithAchievements();
        self.renderPlayer();

        let totalAccumulated = savedScores[playerName].toLocaleString('en-US');

        let fullMessage = `
            ${message}<br><br>
            Tiền thưởng lượt này của <strong class="text-dark">${playerName}</strong> là:<br>
            <strong class='text-danger' style='font-size: 32px;'>${prizeStr}</strong><br><br>
            <span class='text-success fw-bold' style='font-size: 20px;'>Tổng tiền tích lũy: $${totalAccumulated}</span>
        `;

        self.showAlert(fullMessage, function() {
            $('#stopGameBtn').hide();
            self.switchScreen('screen_welcome');
        });
    },

    renderMoneyTree: function() {
        let count = this.state.settings.questionCount;
        let treeHtml = '';
        for (let i = count; i >= 1; i--) {
            let prizeStr = GameConfig.prizes[i] || "$0";
            let msClass = 'mt-normal';
            if (i === 15 || i === 10 || i === 5) msClass = 'mt-milestone';

            treeHtml += `<div class="question mt-level ${msClass}"><div class="mt-level-inner">${i} &bull; ${prizeStr}</div></div>`;
        }
        $('#questions_area').html(treeHtml);
    },

    updateMoneyTree: function() {
        var self = this;
        $('#questions_area .mt-level').removeClass('current-level mt-warm');
        if (self.state.currentPlayer) {
            let count = self.state.settings.questionCount;
            let childIndex = count - self.state.currentQuestionIndex;

            $('#questions_area .mt-level:nth-child(' + childIndex + ')').addClass('current-level');
            $('#questions_area .mt-level').each(function(index) {
                if (index > childIndex - 1) $(this).addClass('mt-warm');
            });
        }
    },

    switchScreen: function(screenId) {
        var self = this;
        $(".game-screen").hide();
        $("#" + screenId).fadeIn();
        if(screenId === 'screen_welcome') {
            this.renderLeaderboard();
            self.playBgMusic({'url':self.audio.gioithieu}, () => {});
        }
    },

    renderPlayer: function () {
        var self = this;
        let playerContainer = $('#player_list');

        let playerHtmlArr = self.state.players.map((p, i) => {
            let pClass = (self.state.currentPlayer && p.id == self.state.currentPlayer.id) ? 'active' : '';
            let prizeStr = p.score !== null ? '$' + p.score.toLocaleString('en-US') : "";
            return '<div class="player '+ pClass +'" data-id="'+p.id+'">'+p.name+'<span>'+prizeStr+'</span></div>'
        });
        playerContainer.html(playerHtmlArr.join(''));

        if(self.state.currentPlayer) {
            let activeEl = playerContainer.find('.player.active').get(0);
            if(activeEl) activeEl.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }

        self.renderLeaderboard();
    },

    renderLeaderboard: function() {
        let sortedPlayers = [...this.state.players].filter(p => p.score !== null && p.score > 0).sort((a, b) => b.score - a.score);

        let html = sortedPlayers.length > 0
            ? sortedPlayers.map((p, idx) => `<li class="py-1"><strong>#${idx + 1}</strong> ${p.name} - <span class="text-warning fw-bold">$${p.score.toLocaleString('en-US')}</span></li>`).join('')
            : "<li class='py-1 text-white-50'>Chưa có người chơi nào</li>";

        $(document).find('#leaderboardList').html(html);
    },

    setCurrentPlayer: function (playerIdx) {
        this.stopMusic();
        this.state.currentPlayer = this.state.players[playerIdx];
        this.renderPlayer();
    },
    playBgMusic: function(args = {}, onEndedCallback) {
        var self = this;
        const defaults = {
            url: '',
            startOn: 0,
            endOn: false,
            volume: 0.5,
            loop: true
        };
        args = { ...defaults, ...args };


        self.stopBgMusic();


        if(!self.state.settings.bgMusic) args.volume = 0;

        var audio = document.getElementById("bg-music-player");
        if (audio) {
            $(audio).find("source").attr("src", args.url);
            audio.load();
            audio.currentTime = args.startOn; // Tua về đầu
            audio.loop = args.loop;
            audio.volume = args.volume;
            audio.play().catch(e => console.log("Cần tương tác để phát nhạc:", e));

            $(audio).off("ended").on("ended", function() {
                self.stopBgMusic();
                if (onEndedCallback) onEndedCallback();
            });

            if(args.endOn) {
                setTimeout(function () {
                    $(audio).trigger("ended");
                }, (args.endOn - args.startOn) * 1000);
            }

        }
    },

    stopBgMusic: function() {
        var audio = document.getElementById("bg-music-player");
        if (audio) {
            audio.pause();
            audio.currentTime = 0; // Tua về đầu
        }
    },
    playMusic: function(args = {}, onEndedCallback) {
        var self = this;
        const defaults = {
            url: '',
            startOn: 0,
            endOn: false,
            volume: 1,
            loop: false
        };
        args = { ...defaults, ...args };

        var audio = document.getElementById("music-player");
        if (audio) {
            $(audio).find("source").attr("src", args.url);
            audio.load();
            audio.loop = args.loop;
            audio.play().catch(e => console.log("Cần tương tác để phát nhạc:", e));

            $(audio).off("ended").on("ended", function() {
                audio.pause();
                audio.currentTime = 0; // Tua về đầu
                if (onEndedCallback) onEndedCallback();
            });
        }
    },

    stopMusic: function () {
        var audio = document.getElementById("music-player");
        if (audio) {
            audio.pause();
            audio.currentTime = 0; // Tua về đầu
        }
    }
};

$(document).ready(function() {
    GameApp.init();
});